#include <bits/stdc++.h>
using namespace std;
int n,m;
string s[10];
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		cin>>s[i];
	}
	sort(s+1,s+1+n);
	do {
		bool flag=0;
		for(int i=1; i<n; i++) {
			int cot=0;
			for(int j=0; j<m; j++) {
				if(s[i][j]!=s[i+1][j]) {
					cot++;
					if(cot>1) {
						flag=1;
						break;
					}
				}
			}
			if(cot==0||cot>1) flag=1;
		}
		if(!flag) {
			cout<<"Yes";
			return 0;
		}
	} while(next_permutation(s+1,s+1+n));
	cout<<"No";
	return 0;
}
